from flask import Flask, request, redirect, url_for, session
from functools import wraps
import pyotp

app = Flask(__name__)
app.config['SECRET_KEY'] = 'super-secret'  # Replace this with your own secret key

# Sample users database. In reality, you would want to replace these with actual user data stored in a secure way.
users = {
    "admin": {"password": "password", "mfa_secret": "MFRUHI23895764"}  # MFA secret for the example
}

def check_auth(username, password):
    user = users.get(username)
    return user is not None and user["password"] == password

def validate_mfa(username, mfa_code):
    user = users.get(username)
    totp = pyotp.TOTP(user['mfa_secret'])
    return totp.verify(mfa_code)

# Decorator to check if user is authenticated
def requires_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        if 'username' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated

@app.route('/')
def home():
    return "Hello, World!"

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        if check_auth(username, password):
            session['username'] = username
            return redirect(url_for('verify_mfa'))  # Redirect to MFA verification page
    return "Please login"

@app.route('/logout')
def logout():
    if 'username' in session:
        session.pop('username', None)
    return redirect(url_for('home'))

@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if request.method == 'POST':
        mfa_code = request.form.get('mfa_code')
        if validate_mfa(session['username'], mfa_code):
            return redirect(url_for('home'))  # Redirect to home page after successful verification
    return "Please enter your MFA code"

@app.route('/protected')
@requires_auth
def protected():
    return "You are authenticated!"